260→export const CodeMirrorEditor = forwardRef<
261→  CodeMirrorEditorHandle,
262→  CodeMirrorEditorProps
263→>(function CodeMirrorEditor({ value, onChange, onValidationChange, isDarkMode = false, onSnippetRequest }, ref) {
264→  const containerRef = useRef<HTMLDivElement>(null);
265→  const viewRef = useRef<EditorView | null>(null);
266→  const onChangeRef = useRef(onChange);
267→  const onValidationChangeRef = useRef(onValidationChange);
268→  const onSnippetRequestRef = useRef(onSnippetRequest);
269→  const isExternalUpdate = useRef(false);
270→
271→  const themeCompartment = useMemo(() => new Compartment(), []);
272→  const highlightCompartment = useMemo(() => new Compartment(), []);
273→
274→  onChangeRef.current = onChange;
275→  onValidationChangeRef.current = onValidationChange;
276→  onSnippetRequestRef.current = onSnippetRequest;
277→
278→  useImperativeHandle(ref, () => ({
279→    getValue: () => viewRef.current?.state.doc.toString() ?? '',
280→    setValue: (val: string) => {
281→      const view = viewRef.current;
282→      if (!view) return;
283→      isExternalUpdate.current = true;
284→      view.dispatch({
285→        changes: { from: 0, to: view.state.doc.length, insert: val },
286→      });
287→      isExternalUpdate.current = false;
288→    },
289→    getView: () => viewRef.current,
290→  }));
291→
292→  useEffect(() => {
293→    if (!containerRef.current) return;
294→
295→    const json5ParseLinter = linter(
296→      (view): Diagnostic[] => {
297→        const doc = view.state.doc.toString();
298→        if (!doc.trim()) return [];
299→        try {
300→          JSON5.parse(doc);
301→          onValidationChangeRef.current?.(false, null);
302→          return [];
303→        } catch (e) {
304→          const msg = (e as SyntaxError).message || 'Invalid JSON';
305→          const lineMatch = msg.match(/at (\d+):(\d+)/);
306→          let from = 0;
307→          let to = Math.min(doc.length, 1);
308→          if (lineMatch) {
309→            const line = parseInt(lineMatch[1], 10);
310→            const col = parseInt(lineMatch[2], 10);
311→            const lineInfo = view.state.doc.line(Math.min(line, view.state.doc.lines));
312→            from = lineInfo.from + Math.min(col - 1, lineInfo.length);
313→            to = Math.min(from + 1, lineInfo.to);
314→          }
315→          onValidationChangeRef.current?.(true, msg);
316→          return [{ from, to, severity: 'error', message: msg, source: 'json5' }];
317→        }
318→      },
319→      { delay: 300 },
320→    );
321→
322→    const schemaLinter = linter(sduiSchemaLinter, { delay: 500 });
323→
324→    const updateListener = EditorView.updateListener.of(update => {
325→      if (update.docChanged && !isExternalUpdate.current) {
326→        const doc = update.state.doc.toString();
327→        onChangeRef.current(doc);
328→      }
329→    });
330→
331→    const initialTheme = isDarkMode ? darkTheme : lightTheme;
332→    const initialHighlight = isDarkMode
333→      ? syntaxHighlighting(darkHighlightStyle)
334→      : syntaxHighlighting(defaultHighlightStyle, { fallback: true });
335→
336→    const state = EditorState.create({
337→      doc: value,
338→      extensions: [
339→        lineNumbers(),
340→        highlightActiveLineGutter(),
341→        highlightActiveLine(),
342→        drawSelection(),
343→        rectangularSelection(),
344→        bracketMatching(),
345→        foldGutter(),
346→        highlightSelectionMatches(),
347→        history(),
348→        javascript(),
349→        highlightCompartment.of(initialHighlight),
350→        lintGutter(),
351→        json5ParseLinter,
352→        schemaLinter,
353→        sduiAutocompletion(),
354→        themeCompartment.of(initialTheme),
355→        updateListener,
356→        keymap.of([
357→          {
358→            key: 'Mod-k',
359→            run: () => {
360→              onSnippetRequestRef.current?.();
361→              return true;
362→            },
363→          },
364→          ...completionKeymap,
365→          indentWithTab,
366→          ...defaultKeymap,
367→          ...historyKeymap,
368→          ...foldKeymap,
369→          ...searchKeymap,
370→        ]),
371→        EditorView.lineWrapping,
372→        EditorState.tabSize.of(2),
373→      ],
374→    });
375→
376→    const view = new EditorView({
377→      state,
378→      parent: containerRef.current,
379→    });
380→
381→    viewRef.current = view;
382→
383→    return () => {
384→      view.destroy();
385→      viewRef.current = null;
386→    };
387→  // eslint-disable-next-line react-hooks/exhaustive-deps
388→  }, []);
389→
390→  useEffect(() => {
391→    const view = viewRef.current;
392→    if (!view) return;
393→
394→    const newTheme = isDarkMode ? darkTheme : lightTheme;
395→    const newHighlight = isDarkMode
396→      ? syntaxHighlighting(darkHighlightStyle)
397→      : syntaxHighlighting(defaultHighlightStyle, { fallback: true });
398→
399→    view.dispatch({
400→      effects: [
401→        themeCompartment.reconfigure(newTheme),
402→        highlightCompartment.reconfigure(newHighlight),
403→      ],
404→    });
405→  }, [isDarkMode, themeCompartment, highlightCompartment]);
406→
407→  useEffect(() => {
408→    const view = viewRef.current;
409→    if (!view) return;
410→    const currentDoc = view.state.doc.toString();
411→    if (currentDoc !== value && value) {
412→      isExternalUpdate.current = true;
413→      view.dispatch({
414→        changes: { from: 0, to: view.state.doc.length, insert: value },
415→      });
416→      isExternalUpdate.current = false;
417→    }
418→  }, [value]);
419→
420→  return (
421→    <div
422→      ref={containerRef}
423→      style={{ height: '100%', overflow: 'hidden' }}
424→    />
425→  );
426→});
