import React, {
  forwardRef,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
} from 'react';
import { EditorState, Compartment } from '@codemirror/state';
import { EditorView, keymap, lineNumbers, highlightActiveLine, highlightActiveLineGutter, drawSelection, rectangularSelection } from '@codemirror/view';
import { javascript } from '@codemirror/lang-javascript';
import { defaultKeymap, history, historyKeymap, indentWithTab } from '@codemirror/commands';
import { syntaxHighlighting, defaultHighlightStyle, bracketMatching, foldGutter, foldKeymap, HighlightStyle } from '@codemirror/language';
import { linter, lintGutter, type Diagnostic } from '@codemirror/lint';
import { searchKeymap, highlightSelectionMatches } from '@codemirror/search';
import { completionKeymap } from '@codemirror/autocomplete';
import { tags } from '@lezer/highlight';
import JSON5 from 'json5';
import { sduiSchemaLinter } from './sduiLinter';
import { sduiAutocompletion } from './sduiAutocomplete';

export interface CodeMirrorEditorHandle {
  getValue: () => string;
  setValue: (value: string) => void;
  getView: () => EditorView | null;
}

interface CodeMirrorEditorProps {
  value: string;
  onChange: (value: string) => void;
  onValidationChange?: (hasErrors: boolean, message: string | null) => void;
  isDarkMode?: boolean;
  onSnippetRequest?: () => void;
}

const darkTheme = EditorView.theme({
  '&': {
    height: '100%',
    fontSize: '12px',
    backgroundColor: '#1e1e1e',
    color: '#d4d4d4',
  },
  '.cm-scroller': {
    fontFamily: "'Ubuntu Mono', 'Menlo', 'Monaco', 'Consolas', monospace",
    lineHeight: '1.5',
    overflow: 'auto',
  },
  '.cm-content': {
    caretColor: '#528bff',
    padding: '4px 0',
  },
  '.cm-gutters': {
    background: '#252526',
    borderRight: '1px solid #3c3c3c',
    color: '#858585',
    minWidth: '32px',
  },
  '.cm-activeLineGutter': {
    background: '#2a2d2e',
  },
  '.cm-activeLine': {
    background: '#2a2d2e',
  },
  '.cm-selectionBackground': {
    background: '#264f78 !important',
  },
  '.cm-cursor': {
    borderLeftColor: '#d4d4d4',
  },
  '.cm-matchingBracket': {
    background: '#3b514d',
    outline: '1px solid #5a7a6f',
  },
  '.cm-foldGutter .cm-gutterElement': {
    cursor: 'pointer',
    padding: '0 4px',
    color: '#858585',
  },
  '.cm-lint-marker': {
    width: '10px',
    height: '10px',
  },
  '.cm-lintRange-error': {
    backgroundImage: 'none',
    textDecoration: 'underline wavy #f44747',
    textUnderlineOffset: '3px',
  },
  '.cm-lintRange-warning': {
    backgroundImage: 'none',
    textDecoration: 'underline wavy #cca700',
    textUnderlineOffset: '3px',
  },
  '.cm-diagnostic': {
    padding: '4px 8px',
    fontSize: '12px',
    background: '#252526',
    color: '#d4d4d4',
  },
  '.cm-diagnostic-error': {
    borderLeft: '3px solid #f44747',
  },
  '.cm-diagnostic-warning': {
    borderLeft: '3px solid #cca700',
  },
  '.cm-tooltip': {
    border: '1px solid #3c3c3c',
    borderRadius: '4px',
    boxShadow: '0 2px 8px rgba(0,0,0,0.36)',
    background: '#252526',
    color: '#d4d4d4',
  },
  '.cm-panels': {
    background: '#252526',
    color: '#d4d4d4',
  },
  '.cm-panels.cm-panels-top': {
    borderBottom: '1px solid #3c3c3c',
  },
  '.cm-search label': {
    color: '#d4d4d4',
  },
  '.cm-textfield': {
    background: '#3c3c3c',
    color: '#d4d4d4',
    border: '1px solid #555',
  },
  '.cm-button': {
    background: '#3c3c3c',
    color: '#d4d4d4',
    border: '1px solid #555',
  },
  '.cm-tooltip-autocomplete': {
    border: '1px solid #3c3c3c',
    borderRadius: '4px',
    boxShadow: '0 2px 8px rgba(0,0,0,0.36)',
    background: '#252526',
    color: '#d4d4d4',
  },
  '.cm-tooltip-autocomplete > ul > li': {
    padding: '2px 8px',
    lineHeight: '1.6',
  },
  '.cm-tooltip-autocomplete > ul > li[aria-selected]': {
    background: '#094771',
    color: '#ffffff',
  },
  '.cm-completionLabel': {
    color: '#d4d4d4',
  },
  '.cm-completionDetail': {
    color: '#858585',
    fontStyle: 'italic',
    marginLeft: '8px',
  },
  '.cm-completionIcon': {
    color: '#569cd6',
  },
}, { dark: true });

const darkHighlightStyle = HighlightStyle.define([
  { tag: tags.propertyName, color: '#9cdcfe' },
  { tag: tags.string, color: '#ce9178' },
  { tag: tags.number, color: '#b5cea8' },
  { tag: tags.bool, color: '#569cd6' },
  { tag: tags.null, color: '#569cd6' },
  { tag: tags.keyword, color: '#569cd6' },
  { tag: tags.punctuation, color: '#d4d4d4' },
  { tag: tags.bracket, color: '#ffd700' },
]);

const lightTheme = EditorView.theme({
  '&': {
    height: '100%',
    fontSize: '12px',
  },
  '.cm-scroller': {
    fontFamily: "'Ubuntu Mono', 'Menlo', 'Monaco', 'Consolas', monospace",
    lineHeight: '1.5',
    overflow: 'auto',
  },
  '.cm-content': {
    caretColor: '#528bff',
    padding: '4px 0',
  },
  '.cm-gutters': {
    background: '#f5f5f5',
    borderRight: '1px solid #e0e0e0',
    color: '#999',
    minWidth: '32px',
  },
  '.cm-activeLineGutter': {
    background: '#e8f0fe',
  },
  '.cm-activeLine': {
    background: '#f0f4ff',
  },
  '.cm-selectionBackground': {
    background: '#d7e4f9 !important',
  },
  '.cm-cursor': {
    borderLeftColor: '#528bff',
  },
  '.cm-matchingBracket': {
    background: '#c8e6c9',
    outline: '1px solid #81c784',
  },
  '.cm-foldGutter .cm-gutterElement': {
    cursor: 'pointer',
    padding: '0 4px',
  },
  '.cm-lint-marker': {
    width: '10px',
    height: '10px',
  },
  '.cm-lintRange-error': {
    backgroundImage: 'none',
    textDecoration: 'underline wavy #e53935',
    textUnderlineOffset: '3px',
  },
  '.cm-lintRange-warning': {
    backgroundImage: 'none',
    textDecoration: 'underline wavy #fb8c00',
    textUnderlineOffset: '3px',
  },
  '.cm-diagnostic': {
    padding: '4px 8px',
    fontSize: '12px',
  },
  '.cm-diagnostic-error': {
    borderLeft: '3px solid #e53935',
  },
  '.cm-diagnostic-warning': {
    borderLeft: '3px solid #fb8c00',
  },
  '.cm-tooltip': {
    border: '1px solid #e0e0e0',
    borderRadius: '4px',
    boxShadow: '0 2px 8px rgba(0,0,0,0.12)',
  },
  '.cm-tooltip-autocomplete': {
    border: '1px solid #e0e0e0',
    borderRadius: '4px',
    boxShadow: '0 2px 8px rgba(0,0,0,0.12)',
    background: '#ffffff',
  },
  '.cm-tooltip-autocomplete > ul > li': {
    padding: '2px 8px',
    lineHeight: '1.6',
  },
  '.cm-tooltip-autocomplete > ul > li[aria-selected]': {
    background: '#d6ebff',
    color: '#000000',
  },
  '.cm-completionDetail': {
    color: '#666',
    fontStyle: 'italic',
    marginLeft: '8px',
  },
});

export const CodeMirrorEditor = forwardRef<
  CodeMirrorEditorHandle,
  CodeMirrorEditorProps
>(function CodeMirrorEditor({ value, onChange, onValidationChange, isDarkMode = false, onSnippetRequest }, ref) {
  const containerRef = useRef<HTMLDivElement>(null);
  const viewRef = useRef<EditorView | null>(null);
  const onChangeRef = useRef(onChange);
  const onValidationChangeRef = useRef(onValidationChange);
  const onSnippetRequestRef = useRef(onSnippetRequest);
  const isExternalUpdate = useRef(false);

  const themeCompartment = useMemo(() => new Compartment(), []);
  const highlightCompartment = useMemo(() => new Compartment(), []);

  onChangeRef.current = onChange;
  onValidationChangeRef.current = onValidationChange;
  onSnippetRequestRef.current = onSnippetRequest;

  useImperativeHandle(ref, () => ({
    getValue: () => viewRef.current?.state.doc.toString() ?? '',
    setValue: (val: string) => {
      const view = viewRef.current;
      if (!view) return;
      isExternalUpdate.current = true;
      view.dispatch({
        changes: { from: 0, to: view.state.doc.length, insert: val },
      });
      isExternalUpdate.current = false;
    },
    getView: () => viewRef.current,
  }));

  useEffect(() => {
    if (!containerRef.current) return;

    const json5ParseLinter = linter(
      (view): Diagnostic[] => {
        const doc = view.state.doc.toString();
        if (!doc.trim()) return [];
        try {
          JSON5.parse(doc);
          onValidationChangeRef.current?.(false, null);
          return [];
        } catch (e) {
          const msg = (e as SyntaxError).message || 'Invalid JSON';
          const lineMatch = msg.match(/at (\d+):(\d+)/);
          let from = 0;
          let to = Math.min(doc.length, 1);
          if (lineMatch) {
            const line = parseInt(lineMatch[1], 10);
            const col = parseInt(lineMatch[2], 10);
            const lineInfo = view.state.doc.line(Math.min(line, view.state.doc.lines));
            from = lineInfo.from + Math.min(col - 1, lineInfo.length);
            to = Math.min(from + 1, lineInfo.to);
          }
          onValidationChangeRef.current?.(true, msg);
          return [{ from, to, severity: 'error', message: msg, source: 'json5' }];
        }
      },
      { delay: 300 },
    );

    const schemaLinter = linter(sduiSchemaLinter, { delay: 500 });

    const updateListener = EditorView.updateListener.of(update => {
      if (update.docChanged && !isExternalUpdate.current) {
        const doc = update.state.doc.toString();
        onChangeRef.current(doc);
      }
    });

    const initialTheme = isDarkMode ? darkTheme : lightTheme;
    const initialHighlight = isDarkMode
      ? syntaxHighlighting(darkHighlightStyle)
      : syntaxHighlighting(defaultHighlightStyle, { fallback: true });

    const state = EditorState.create({
      doc: value,
      extensions: [
        lineNumbers(),
        highlightActiveLineGutter(),
        highlightActiveLine(),
        drawSelection(),
        rectangularSelection(),
        bracketMatching(),
        foldGutter(),
        highlightSelectionMatches(),
        history(),
        javascript(),
        highlightCompartment.of(initialHighlight),
        lintGutter(),
        json5ParseLinter,
        schemaLinter,
        sduiAutocompletion(),
        themeCompartment.of(initialTheme),
        updateListener,
        keymap.of([
          {
            key: 'Mod-k',
            run: () => {
              onSnippetRequestRef.current?.();
              return true;
            },
          },
          ...completionKeymap,
          indentWithTab,
          ...defaultKeymap,
          ...historyKeymap,
          ...foldKeymap,
          ...searchKeymap,
        ]),
        EditorView.lineWrapping,
        EditorState.tabSize.of(2),
      ],
    });

    const view = new EditorView({
      state,
      parent: containerRef.current,
    });

    viewRef.current = view;

    return () => {
      view.destroy();
      viewRef.current = null;
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    const view = viewRef.current;
    if (!view) return;

    const newTheme = isDarkMode ? darkTheme : lightTheme;
    const newHighlight = isDarkMode
      ? syntaxHighlighting(darkHighlightStyle)
      : syntaxHighlighting(defaultHighlightStyle, { fallback: true });

    view.dispatch({
      effects: [
        themeCompartment.reconfigure(newTheme),
        highlightCompartment.reconfigure(newHighlight),
      ],
    });
  }, [isDarkMode, themeCompartment, highlightCompartment]);

  useEffect(() => {
    const view = viewRef.current;
    if (!view) return;
    const currentDoc = view.state.doc.toString();
    if (currentDoc !== value && value) {
      isExternalUpdate.current = true;
      view.dispatch({
        changes: { from: 0, to: view.state.doc.length, insert: value },
      });
      isExternalUpdate.current = false;
    }
  }, [value]);

  return (
    <div
      ref={containerRef}
      style={{ height: '100%', overflow: 'hidden' }}
    />
  );
});

