268→function isInsidePropsObject(doc: string, pos: number): boolean {
269→  const before = doc.slice(0, pos);
270→  let depth = 0;
271→  let inStr = false;
272→  let strCh = '';
273→
274→  for (let i = before.length - 1; i >= 0; i--) {
275→    const ch = before[i];
276→
277→    if (inStr) {
278→      if (ch === strCh && (i === 0 || before[i - 1] !== '\\')) inStr = false;
279→      continue;
280→    }
281→    if (ch === '"' || ch === "'") { inStr = true; strCh = ch; continue; }
282→
283→    if (ch === '}') depth++;
284→    if (ch === '{') {
285→      depth--;
286→      if (depth < 0) {
287→        const preceding = before.slice(Math.max(0, i - 30), i).trim();
288→        return /["']props["']\s*:\s*$/.test(preceding);
289→      }
290→    }
291→  }
292→  return false;
293→}
294→
295→function getComponentTypeForPropsAt(doc: string, pos: number): string | null {
296→  const before = doc.slice(0, pos);
297→  let depth = 0;
298→
299→  for (let i = before.length - 1; i >= 0; i--) {
300→    if (before[i] === '}') depth++;
301→    if (before[i] === '{') {
302→      depth--;
303→      if (depth < 0) {
304→        const outerStart = before.lastIndexOf('{', i - 1);
305→        if (outerStart >= 0) {
306→          const outerChunk = doc.slice(outerStart, outerStart + 300);
307→          const typeMatch = outerChunk.match(/"type"\s*:\s*"([^"]+)"/);
308→          if (typeMatch?.[1] && (knownTypes as readonly string[]).includes(typeMatch[1])) {
309→            return typeMatch[1];
310→          }
311→        }
312→        break;
313→      }
314→    }
315→  }
316→  return null;
317→}
318→
319→function isInsideComponentObject(doc: string, pos: number): boolean {
320→  const before = doc.slice(0, pos);
321→  let depth = 0;
322→
323→  for (let i = before.length - 1; i >= 0; i--) {
324→    if (before[i] === '}' || before[i] === ']') depth++;
325→    if (before[i] === '{' || before[i] === '[') {
326→      depth--;
327→      if (depth < 0) {
328→        if (before[i] === '[') {
329→          const preceding = before.slice(Math.max(0, i - 30), i).trim();
330→          return /["']body["']\s*:\s*$/.test(preceding);
331→        }
332→        const preceding = before.slice(Math.max(0, i - 30), i).trim();
333→        if (/,\s*$/.test(preceding) || /\[\s*$/.test(preceding)) {
334→          const bracketSearch = before.slice(0, i);
335→          const bracketPos = bracketSearch.lastIndexOf('[');
336→          if (bracketPos >= 0) {
337→            const beforeBracket = bracketSearch.slice(Math.max(0, bracketPos - 30), bracketPos).trim();
338→            return /["']body["']\s*:\s*$/.test(beforeBracket);
339→          }
340→        }
341→        return false;
342→      }
343→    }
344→  }
345→  return false;
346→}
347→
348→function isInsideTopLevelObject(doc: string, pos: number): boolean {
349→  const before = doc.slice(0, pos);
350→  let depth = 0;
351→
352→  for (let i = before.length - 1; i >= 0; i--) {
353→    if (before[i] === '}' || before[i] === ']') depth++;
354→    if (before[i] === '{' || before[i] === '[') {
355→      depth--;
356→      if (depth < 0) {
357→        if (before[i] === '{') {
358→          const preceding = before.slice(0, i).trim();
359→          return preceding.length === 0;
360→        }
361→        return false;
362→      }
363→    }
364→  }
365→  return false;
366→}
367→
368→function getExistingKeysInObject(doc: string, pos: number): Set<string> {
369→  const keys = new Set<string>();
370→  const before = doc.slice(0, pos);
371→  let depth = 0;
372→  let objStart = -1;
373→
374→  for (let i = before.length - 1; i >= 0; i--) {
375→    if (before[i] === '}' || before[i] === ']') depth++;
376→    if (before[i] === '{' || before[i] === '[') {
377→      depth--;
378→      if (depth < 0) {
379→        objStart = i;
380→        break;
381→      }
382→    }
383→  }
384→
385→  if (objStart < 0) return keys;
386→
387→  let endBrace = doc.indexOf('}', pos);
388→  if (endBrace < 0) endBrace = doc.length;
389→  const objectContent = doc.slice(objStart, endBrace + 1);
390→
391→  let keyMatch: RegExpExecArray | null;
392→  const keyRegex = /"([^"]+)"\s*:/g;
393→  while ((keyMatch = keyRegex.exec(objectContent)) !== null) {
394→    keys.add(keyMatch[1]);
395→  }
396→
397→  return keys;
398→}
399→
400→export function sduiAutocompletion() {
401→  return autocompletion({
402→    override: [sduiCompletionSource],
403→    activateOnTyping: true,
404→    maxRenderedOptions: 25,
405→    icons: true,
406→  });
407→}
