const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1400, height: 900 } });

  await page.goto('http://localhost:6006/?path=/story/sdui-voucher-screens--form', { waitUntil: 'networkidle', timeout: 30000 });
  await page.waitForTimeout(3000);

  const editor = page.locator('.cm-editor .cm-content');
  const editorExists = await editor.count();
  console.log('Editor content found:', editorExists > 0);

  if (editorExists > 0) {
    // Click to focus
    await editor.first().click();
    await page.waitForTimeout(300);

    // Select all and replace with a minimal JSON where we can test autocomplete
    await page.keyboard.press('Meta+a');
    await page.waitForTimeout(100);
    await page.keyboard.type('{\"type\": \"', { delay: 20 });
    await page.waitForTimeout(500);

    // Now try Alt+Space to trigger autocomplete for type values
    await page.keyboard.press('Alt+Space');
    await page.waitForTimeout(1000);

    const tooltip = page.locator('.cm-tooltip-autocomplete');
    const tooltipVisible = await tooltip.count();
    console.log('Autocomplete tooltip visible after Alt+Space:', tooltipVisible > 0);

    if (tooltipVisible > 0) {
      await page.screenshot({ path: '.storybook/screenshots/alt-space-autocomplete-working.png', fullPage: false });
      console.log('Screenshot with autocomplete saved');
    } else {
      // Try Ctrl+Space as baseline
      await page.keyboard.press('Control+Space');
      await page.waitForTimeout(1000);
      const tooltipCtrl = page.locator('.cm-tooltip-autocomplete');
      const tooltipCtrlVisible = await tooltipCtrl.count();
      console.log('Autocomplete tooltip visible after Ctrl+Space:', tooltipCtrlVisible > 0);
      await page.screenshot({ path: '.storybook/screenshots/alt-space-autocomplete-test.png', fullPage: false });
    }
  }

  await browser.close();
})();
